# Reverse Digits

## 问题描述

实现一个函数，输入非负整数 `n`，返回它的十进制数字反转后的整数。

约定：

- `n >= 0`
- `reverse_digits(0) = 0`
- 使用 `% 10` 和 `/ 10` 逐位处理

## 正确代码

```c
int reverse_digits(int n) {
    int ans = 0;

    while (n > 0) {
        ans = ans * 10 + n % 10;
        n = n / 10;
    }

    return ans;
}
```

## 说明

这是最简单的数位反转题，适合验证“数位循环 + 累积构造”。

#include "../../verification_stdlib.h"

/*@ Extern Coq (digit_sum_z : Z -> Z) */
/*@ Import Coq Require Import digit_sum */

int digit_sum(int n)
/*@ Require
      0 <= n && n <= INT_MAX && emp
    Ensure
      __return == digit_sum_z(n@pre) && emp
*/
{
    int sum = 0;

    while (n > 0) {
        sum += n % 10;
        n = n / 10;
    }

    return sum;
}

#include "../../verification_stdlib.h"

/*@ Extern Coq (count_divisors_spec : Z -> Z) */
/*@ Import Coq Require Import count_divisors */

int count_divisors(int n)
/*@ Require
      1 <= n && n < INT_MAX && emp
    Ensure
      __return == count_divisors_spec(n@pre) && emp
*/
{
    int d;
    int cnt = 0;

    for (d = 1; d <= n; ++d) {
        if (n % d == 0) {
            cnt++;
        }
    }

    return cnt;
}
Require Import ZArith.

Open Scope Z_scope.

Fixpoint count_divisors_upto (n : Z) (fuel : nat) : Z :=
  match fuel with
  | O => 0
  | S k =>
      count_divisors_upto n k +
      (if Z.eq_dec (Z.rem n (Z.of_nat (S k))) 0 then 1 else 0)
  end.

Definition count_divisors_spec (n : Z) : Z :=
  count_divisors_upto n (Z.to_nat n).

#include "../../verification_stdlib.h"

/*@ Extern Coq (fib_z: Z -> Z) */
/*@ Import Coq Require Import fibonacci */

int fibonacci(int n)
/*@ Require
      0 <= n && n <= 46 && emp
    Ensure
      __return == fib_z(n@pre) && emp
*/
{
    int i;
    int a = 0;
    int b = 1;
    int c;

    if (n == 0) {
        return 0;
    }

    for (i = 2; i <= n; ++i) {
        c = a + b;
        a = b;
        b = c;
    }

    return b;
}
Require Import ZArith.

Open Scope Z_scope.

Fixpoint fib_pair (n : nat) : Z * Z :=
  match n with
  | O => (0, 1)
  | S k =>
      let p := fib_pair k in
      (snd p, fst p + snd p)
  end.

Definition fib_nat (n : nat) : Z :=
  fst (fib_pair n).

Definition fib_z (n : Z) : Z :=
  fib_nat (Z.to_nat n).

#include "../../verification_stdlib.h"

/*@ Extern Coq (reverse_digits_z : Z -> Z) */
/*@ Import Coq Require Import reverse_digits */

int reverse_digits(int n)
/*@ Require
      0 <= n && n <= INT_MAX &&
      reverse_digits_z(n) <= INT_MAX &&
      emp
    Ensure
      __return == reverse_digits_z(n@pre) && emp
*/
{
    int ans = 0;

    while (n > 0) {
        ans = ans * 10 + n % 10;
        n = n / 10;
    }

    return ans;
}
